/**
 * Results Statistics Database
 * All A-star/A rates are CUMULATIVE percentages.
 * For 9-1: grade8Rate = Grade9(ind) + Grade8(ind), etc.
 * AS/A2 duplicates merged. Names Title-Cased.
 */
import ocrOfficial from './official/ocr-results-statistics.json';
import aqaOfficialMath from './official/aqa-math-results-statistics.json';

export interface YearlyStats {
  year: number;
  series: "june" | "november" | "march" | "summer" | "january" | "autumn";
  aStarRate: number; aRate: number; bRate: number; cRate: number; dRate: number; eRate: number;
  grade9Rate?: number; grade8Rate?: number; grade7Rate?: number; grade6Rate?: number;
  grade5Rate?: number; grade4Rate?: number; grade3Rate?: number; grade2Rate?: number; grade1Rate?: number;
  entries?: number;
  rawGradeRates?: Partial<Record<"grade9Rate" | "grade8Rate" | "grade7Rate" | "grade6Rate" | "grade5Rate" | "grade4Rate" | "grade3Rate" | "grade2Rate" | "grade1Rate", number>>;
  normalizationIssues?: string[];
}
export interface SubjectStats { code: string; name: string; board: string; level: "A-Level" | "IGCSE" | "GCSE" | "FSMQ"; years: YearlyStats[]; }

function y(year: number, series: "june" | "november" | "march" | "summer" | "january" | "autumn",
  aStar: number, a: number, b: number, c: number, d: number, e: number,
  g9?: number, g8?: number, g7?: number, g6?: number, g5?: number,
  g4?: number, g3?: number, g2?: number, g1?: number, entries?: number): YearlyStats {
  const r: YearlyStats = { year, series, aStarRate: aStar, aRate: a, bRate: b, cRate: c, dRate: d, eRate: e, entries };
  const gRates: (number | undefined)[] = [g9, g8, g7, g6, g5, g4, g3, g2, g1];
  const keys: (keyof YearlyStats)[] = ['grade9Rate', 'grade8Rate', 'grade7Rate', 'grade6Rate', 'grade5Rate', 'grade4Rate', 'grade3Rate', 'grade2Rate', 'grade1Rate'];

  let prev = 0;
  const rawGradeRates: YearlyStats["rawGradeRates"] = {};
  const normalizationIssues: string[] = [];
  for (let i = 0; i < gRates.length; i++) {
    const v = gRates[i];
    if (v !== undefined) {
      // 9-1 累积率必须单调不减（值越大表示等级越低、包含学生越多）
      rawGradeRates[keys[i] as keyof NonNullable<YearlyStats["rawGradeRates"]>] = v;
      const normalized = Math.max(v, prev);
      if (normalized !== v) normalizationIssues.push(`${String(keys[i])}: raw ${v}, normalized ${normalized}`);
      (r as unknown as Record<string, unknown>)[keys[i]] = normalized;
      prev = normalized;
    }
  }
  if (normalizationIssues.length) {
    r.rawGradeRates = rawGradeRates;
    r.normalizationIssues = normalizationIssues;
  }
  return r;
}
function s(code: string, name: string, board: string, level: "A-Level" | "IGCSE" | "GCSE" | "FSMQ", years: YearlyStats[]): SubjectStats {
  // Legacy generated A-Level rows passed entries in the first optional 9-1
  // slot. Repair that mapping centrally; A-Level/FSMQ never use 9-1 fields.
  if (level === "A-Level" || level === "FSMQ") {
    years = years.map(year => {
      if (year.entries !== undefined || year.grade9Rate === undefined) return year;
      const repaired = { ...year, entries: year.grade9Rate };
      repaired.normalizationIssues = [...(year.normalizationIssues ?? []), "legacy entries value migrated from grade9Rate"];
      delete repaired.grade9Rate;
      delete repaired.grade8Rate;
      delete repaired.grade7Rate;
      delete repaired.grade6Rate;
      delete repaired.grade5Rate;
      delete repaired.grade4Rate;
      delete repaired.grade3Rate;
      delete repaired.grade2Rate;
      delete repaired.grade1Rate;
      return repaired;
    });
  }
  return { code, name, board, level, years };
}

