type OfficialOcrRow = {
  code: string;
  name: string;
  year: number;
  rates: number[];
  entries: number;
};

function officialOcrYear(row: OfficialOcrRow, level: 'A-Level' | 'GCSE'): YearlyStats {
  const [r1, r2, r3, r4, r5, r6, r7, r8, r9] = row.rates;
  if (level === 'GCSE') {
    return {
      year: row.year,
      series: 'june',
      aStarRate: r1,
      aRate: r2,
      bRate: r3,
      cRate: r4,
      dRate: r5,
      eRate: r6,
      grade9Rate: r1,
      grade8Rate: r2,
      grade7Rate: r3,
      grade6Rate: r4,
      grade5Rate: r5,
      grade4Rate: r6,
      grade3Rate: r7,
      grade2Rate: r8,
      grade1Rate: r9,
      entries: row.entries,
    };
  }
  return {
    year: row.year,
    series: 'june',
    aStarRate: r1,
    aRate: r2,
    bRate: r3,
    cRate: r4,
    dRate: r5,
    eRate: r6,
    entries: row.entries,
  };
}

function groupOfficialOcr(rows: OfficialOcrRow[], level: 'A-Level' | 'GCSE'): SubjectStats[] {
  const grouped = new Map<string, SubjectStats>();
  for (const row of rows) {
    const current = grouped.get(row.code) ?? {
      code: row.code,
      name: row.name,
      board: 'OCR',
      level,
      years: [],
    };
    current.years.push(officialOcrYear(row, level));
    grouped.set(row.code, current);
  }
  return [...grouped.values()].map(subject => ({
    ...subject,
    years: subject.years.sort((a, b) => b.year - a.year),
  }));
}

const OCR_OFFICIAL_STATS: SubjectStats[] = [
  ...groupOfficialOcr(ocrOfficial.aLevel as OfficialOcrRow[], 'A-Level'),
  ...groupOfficialOcr(ocrOfficial.gcse as OfficialOcrRow[], 'GCSE'),
];

function withoutSupersededOcrRows(subjects: SubjectStats[]): SubjectStats[] {
  return subjects.map(subject => subject.board !== 'OCR' ? subject : ({
    ...subject,
    years: subject.years.filter(year =>
      year.series !== 'june' || year.year < 2021 || year.year > 2025
    ),
  })).filter(subject => subject.years.length > 0);
}

