/** Raw rows requiring source review. They remain traceable and are never
 * silently overwritten; the UI labels any normalized value derived from them. */
export const RESULT_STATISTICS_NORMALIZATION_CANDIDATES = ALL_SUBJECT_STATS.flatMap((subject) =>
  subject.years
    .filter((year) => (year.normalizationIssues?.length ?? 0) > 0)
    .map((year) => ({
      board: subject.board,
      level: subject.level,
      subjectCode: subject.code,
      year: year.year,
      series: year.series,
      rawGradeRates: year.rawGradeRates,
      normalizedGradeRates: Object.fromEntries(Object.keys(year.rawGradeRates ?? {}).map((key) => [key, (year as unknown as Record<string, unknown>)[key]])),
      reasons: year.normalizationIssues ?? [],
    })),
);

export function isNineToOne(board: string, level: string): boolean {
  const k = `${board}|${level}`;
  return k === 'Edexcel|IGCSE' || k === 'Edexcel|GCSE' || k === 'Edexcel UK|GCSE' || k === 'AQA|GCSE' || k === 'AQA|Level 2 Certificate' || k === 'OCR|GCSE' || k === 'WJEC/Eduqas|GCSE';
}

export function getSubjectStats(code: string, board: string, level?: string): SubjectStats | undefined {
  const codeAliases: Record<string, string> = {
    WMA: 'YMA01',
    YBI01: 'YBI11', YCH01: 'YCH11', YEC01: 'YEC11', YPH01: 'YPH11',
  };
  const normalizedCode = codeAliases[code] ?? code;
  const normalizedLevel = board === 'AQA' && level === 'Level 2 Certificate'
    ? 'GCSE'
    : board === 'OCR' && level === 'Level 3 FSMQ'
      ? 'FSMQ'
      : board === 'Edexcel' && level === 'GCSE' && /^4/.test(normalizedCode)
        ? 'IGCSE'
        : board === 'CAIE' && level === 'GCSE'
          ? 'IGCSE'
          : level;
  const m = ALL_SUBJECT_STATS.filter(s => s.code === normalizedCode && s.board === board && (!normalizedLevel || s.level === normalizedLevel));
  if (m.length === 0) return undefined; if (m.length === 1) return m[0];
  const seen = new Set<string>(); const merged: YearlyStats[] = [];
  for (const x of m) for (const y of x.years) { const k = `${y.year}-${y.series}`; if (!seen.has(k)) { seen.add(k); merged.push(y); } }
  return { ...m[0], years: merged };
}

export function getSortedSubjects(board: string, level: string): { code: string; name: string }[] {
  const s = ALL_SUBJECT_STATS.filter(x => x.board === board && x.level === level);
  const m = new Map<string, string>();
  for (const x of s) if (!m.has(x.code)) m.set(x.code, x.name);
  let u = Array.from(m.entries()).map(([c, n]) => ({ code: c, name: n }));
  // OCR changed many specification codes while retaining the same subject title.
  // Prefer the code with the newest official series instead of showing duplicate labels.
  if (board === 'OCR') {
    const byName = new Map<string, { code: string; name: string; latest: number }>();
    for (const subject of u) {
      const latest = getSubjectStats(subject.code, board, level)?.years.reduce((max, year) => Math.max(max, year.year), 0) ?? 0;
      const key = subject.name.toLocaleLowerCase('en-GB');
      const current = byName.get(key);
      if (!current || latest > current.latest) byName.set(key, { ...subject, latest });
    }
    u = [...byName.values()].map(({ code, name }) => ({ code, name }));
  }
  const pr = ['Mathematics', 'Further Mathematics', 'Biology', 'Chemistry', 'Physics', 'Economics', 'Business', 'Computer Science', 'Psychology'];
  const p = (n: string) => { const i = pr.findIndex(x => n.toLowerCase().includes(x.toLowerCase())); return i === -1 ? 999 : i; };
  return u.sort((a, b) => { const pa = p(a.name), pb = p(b.name); if (pa !== pb) return pa - pb; return a.code.localeCompare(b.code, undefined, { numeric: true }); });
}

const BOARD_ORDER = ['CAIE', 'Edexcel', 'Edexcel UK', 'AQA', 'OCR', 'WJEC/Eduqas'];
const LEVEL_ORDER = ['IGCSE', 'GCSE', 'A-Level', 'FSMQ'];

export function getAvailableBoards(): string[] {
  return [...new Set(ALL_SUBJECT_STATS.map(s => s.board))]
    .sort((a, b) => BOARD_ORDER.indexOf(a) - BOARD_ORDER.indexOf(b));
}
export function getAvailableLevels(board: string): string[] {
  return [...new Set(ALL_SUBJECT_STATS.filter(s => s.board === board).map(s => s.level))]
    .sort((a, b) => LEVEL_ORDER.indexOf(a) - LEVEL_ORDER.indexOf(b));
}
export function getLevelsForBoard(board: string): string[] { return getAvailableLevels(board); }
export function getAvailableSubjects(board: string, level: string): { code: string; name: string }[] { return getSortedSubjects(board, level); }
